# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor._

case class Deposit(amount: Double)
case class Withdrawal(amount: Double)

class AccountActor extends Actor {
  var balance: Double = 0

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      println(s"Deposited $amount, new balance: $balance")
    case Withdrawal(amount) if (amount > balance) =>
      println(s"Insufficient funds for withdrawal of $amount, current balance: $balance")
    case Withdrawal(amount) =>
      balance -= amount
      println(s"Withdrew $amount, new balance: $balance")
  }
}